import ScrollAnimation from 'react-animate-on-scroll';
import React from "react";
import { slideInLeft, slideInRight } from 'react-animations';
const AboutMe = () => {
    const SlideInLeft = styled.div`animation: 2s ${keyframes`${slideInLeft}`} 1 `;
    const SlideInRight = styled.div`animation: 2s ${keyframes`${slideInRight}`} 1 `;
    return(
        <ScrollAnimation
            animateIn='fadeIn'
            animateOut='fadeOut'>
            <div className="ui center aligned segment">

                <h1 className="ui header" style={{fontWeight:"900"}}>
                    <SlideInLeft>
                        <div style={{display:"inline-block"}}><i className="caret right icon" style={{textAlign:"left",fontSize:"1em"}}/></div>
                    </SlideInLeft>
                    About Me
                    <SlideInRight>
                        <div style={{display:"inline-block"}}><i className="caret left icon" style={{textAlign:"right",fontSize:"1em"}}/></div>
                    </SlideInRight>
                </h1>

            </div>
        </ScrollAnimation>

    )
};
export default AboutMe;
